{
  "mode": "method",
  "tests": [
    {
      "name": "valid_checkpoint_screening",
      "input": {
        "user_id": "jcori",
        "project_id": "30092518"
      },
      "output": {
        "screening_score": "link_to_scorecard"
      },
      "notes": "Validates that the screening score link is displayed correctly when the user is logged in."
    },
    {
      "name": "pending_screening_score",
      "input": {
        "user_id": "jcori",
        "project_id": "30092518"
      },
      "output": {
        "screening_score": "pending"
      },
      "notes": "Tests the scenario where the screening score is still pending."
    },
    {
      "name": "invalid_user_id",
      "input": {
        "user_id": "invalid_user",
        "project_id": "30092518"
      },
      "output": {
        "error": "User not found"
      },
      "notes": "Checks the response when an invalid user ID is provided."
    },
    {
      "name": "invalid_project_id",
      "input": {
        "user_id": "jcori",
        "project_id": "invalid_project"
      },
      "output": {
        "error": "Project not found"
      },
      "notes": "Verifies the response for an invalid project ID."
    },
    {
      "name": "user_not_logged_in",
      "input": {
        "user_id": "guest",
        "project_id": "30092518"
      },
      "output": {
        "error": "User must be logged in"
      },
      "notes": "Ensures that a user must be logged in to access the screening score."
    },
    {
      "name": "multiple_screening_scores",
      "input": {
        "user_id": "jcori",
        "project_id": "30092518"
      },
      "output": {
        "screening_scores": [
          "link_to_scorecard_1",
          "link_to_scorecard_2"
        ]
      },
      "notes": "Tests the scenario where multiple screening scores are available."
    },
    {
      "name": "scorecard_not_accessible",
      "input": {
        "user_id": "jcori",
        "project_id": "30092518"
      },
      "output": {
        "error": "Scorecard not accessible"
      },
      "notes": "Checks the response when the scorecard is not accessible due to permissions."
    },
    {
      "name": "no_screening_phase",
      "input": {
        "user_id": "jcori",
        "project_id": "30092519"
      },
      "output": {
        "error": "No screening phase available"
      },
      "notes": "Validates the response when there is no screening phase in the project."
    }
  ],
  "assumptions": "User must be logged in to access screening scores. Project IDs and User IDs are valid and exist in the system.",
  "notes": "Ensure to test both valid and invalid scenarios to cover edge cases."
}
